class PairingResult { final bool success; final String? deviceId; final String? deviceName; final String? errorMessage; const PairingResult._({required this.success, this.deviceId, this.deviceName, this.errorMessage}); factory PairingResult.success(String deviceId, String deviceName) => PairingResult._(success: true, deviceId: deviceId, deviceName: deviceName); factory PairingResult.failure(String message) => PairingResult._(success: false, errorMessage: message); }